def range_summary(nums):
    if not nums:
        return ''

    runs = []
    current, count = nums[0], 1
    for n in nums[1:]:
        if n == current + 1:
            count += 1
        else:
            runs.append((current, count))
            current = n
            count = 1
    runs.append((current, count))

    result = ', '.join('-'.join(map(str, run)) for run in runs)
    return result if result else ','.join(str(n) for n in nums)
